+// See https://llvm.org/LICENSE.txt for license information.
+// SPDX-License-Identifier: Apache-2.0 WITH LLVM-exception
+//
+//===----------------------------------------------------------------------===//
+//
+// This file implements the visitSelect function.
+//
+//===----------------------------------------------------------------------===//
+
+#include "InstCombineInternal.h"
+#include "llvm/Analysis/AssumptionCache.h"
+#include "llvm/Analysis/CmpInstAnalysis.h"
+#include "llvm/Analysis/InstructionSimplify.h"
+#include "llvm/Analysis/Loads.h"
+#include "llvm/Analysis/TargetLibraryInfo.h"
+#include "llvm/Analysis/ValueTracking.h"
+#include "llvm/IR/PatternMatch.h"
+
+using namespace llvm;
+using namespace PatternMatch;
+
+Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
+  Value *CondVal = SI.getCondition();
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+  Type *SelType = SI.getType();
+
   // select(C, Z, binop(select(C, X, Y), W)) -> select(C, Z, binop(Y, W))
   BinaryOperator *FalseBO;
   if (match(FalseVal, m_OneUse(m_BinOp(FalseBO))) && !FalseBO->isIntDivRem()) {
@@ -3909,6 +3940,20 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     return &SI;
   }

+  // select(C2, select(C1, A, B), select(C1, B, A))
+  //   --> select(xor(C1, C2), B, A)
+  if (auto *TrueSel = dyn_cast<SelectInst>(TrueVal))
+    if (auto *FalseSel = dyn_cast<SelectInst>(FalseVal))
+      if (TrueSel->getCondition() == FalseSel->getCondition() &&
+          TrueSel->getTrueValue() == FalseSel->getFalseValue() &&
+          TrueSel->getFalseValue() == FalseSel->getTrueValue() &&
+          TrueSel->getCondition()->getType()->isIntegerTy(1) &&
+          CondVal->getType()->isIntegerTy(1)) {
+        Value *Xor = Builder.CreateXor(TrueSel->getCondition(), CondVal, "xor");
+        return SelectInst::Create(Xor, TrueSel->getFalseValue(),
+                                  TrueSel->getTrueValue());
+      }
+
   if (Instruction *I = foldVectorSelect(SI))
     return I;

@@ -4081,3 +4126,4 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {

   return nullptr;
 }
+
